(function(w){"use strict";const ID="speed-distance-time";function n(v){return v===null||v===undefined||v===''?NaN:Number(v)}function compute(x){const s=n(x.speed),d=n(x.distance),t=n(x.time),valid=[Number.isFinite(s),Number.isFinite(d),Number.isFinite(t)].filter(Boolean).length;if(valid!==2)return{error:"속력·거리·시간 중 정확히 두 값을 입력해 주세요."};if(!Number.isFinite(s)){if(t===0)return{error:"시간은 0일 수 없습니다."};return{kind:'speed',value:d/t}}if(!Number.isFinite(d))return{kind:'distance',value:s*t};if(s===0)return{error:"속력은 0일 수 없습니다."};return{kind:'time',value:d/s}}
function render(root,api){root.innerHTML=`<div class="hm-calc-panel"><div class="hm-calc-form"><p class="hm-calc-hint">구하려는 값 하나는 비워 두고 나머지 두 값을 입력하세요. 단위는 m/s, m, s 기준입니다.</p><div class="hm-calc-grid-2"><div class="hm-calc-field"><label>속력 (m/s)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>거리 (m)</label><input class="hm-calc-input" inputmode="decimal"></div><div class="hm-calc-field"><label>시간 (s)</label><input class="hm-calc-input" inputmode="decimal"></div></div><div class="hm-calc-actions"><button type="button" class="hm-calc-btn">계산하기</button></div><p class="hm-calc-message" hidden></p></div><div class="hm-calc-result" hidden></div></div>`;const inputs=root.querySelectorAll("input"),go=root.querySelector("button"),msg=root.querySelector(".hm-calc-message"),res=root.querySelector(".hm-calc-result");go.addEventListener("click",()=>{const vals=Array.from(inputs).map(i=>i.value.trim()===''?'':api.parseNumber(i.value)),r=compute({speed:vals[0],distance:vals[1],time:vals[2]});if(r.error){api.setMessage(msg,r.error);api.clearResult(res);return}const unit=r.kind==='speed'?'m/s':r.kind==='distance'?'m':'s',title=r.kind==='speed'?'속력':r.kind==='distance'?'거리':'시간';api.setMessage(msg,"");api.setResult(res,api.resultCard(title,`${api.formatNumber(r.value,8)} ${unit}`));});}
w.HM_CALC.register(ID,{compute,render});})(window);
